package com.evolua.auth.infrastructure.persistence; import jakarta.persistence.*; import java.time.Instant; @Entity @Table(name = "refresh_sessions") public class RefreshSessionEntity { @Id @GeneratedValue(strategy = GenerationType.IDENTITY) private Long id; private String userId; @Column(length = 1024) private String refreshToken; private Instant createdAt; private boolean revoked; public Long getId() { return id; } public void setId(Long id) { this.id = id; } public String getUserId() { return userId; } public void setUserId(String userId) { this.userId = userId; } public String getRefreshToken() { return refreshToken; } public void setRefreshToken(String refreshToken) { this.refreshToken = refreshToken; } public Instant getCreatedAt() { return createdAt; } public void setCreatedAt(Instant createdAt) { this.createdAt = createdAt; } public boolean isRevoked() { return revoked; } public void setRevoked(boolean revoked) { this.revoked = revoked; } }
